func TestGeneratedPrincipalStore_List(t *testing.T) {
	ctx, db, store := setupTestStore(t)
	pgxfixtures.TruncatePublicSchema(t, ctx, db.Pool)

	// Each fixture creates its own FK scope. When List filters by scope,
	// only the matching row is visible; assertions below reflect that.
	const numRecords = 3
	created := fixtures.CreateTestPrincipalWithDefaults(t, ctx, db)
	for i := 1; i < numRecords; i++ {
		fixtures.CreateTestPrincipalWithDefaults(t, ctx, db)
	}
	_ = created

	t.Run("returns records", func(t *testing.T) {
		filter := principals.FilterList{}
		orderBy := fop.NewOrder(principals.DefaultOrderBy, principals.DefaultOrderDirection)
		results, err := store.List(ctx, filter, orderBy, fop.PageStringCursor{}, false)
		require.NoError(t, err)
		assert.GreaterOrEqual(t, len(results), 1)
	})

	t.Run("respects limit", func(t *testing.T) {
		filter := principals.FilterList{}
		orderBy := fop.NewOrder(principals.DefaultOrderBy, principals.DefaultOrderDirection)
		page := fop.PageStringCursor{Limit: 2}
		results, err := store.List(ctx, filter, orderBy, page, false)
		require.NoError(t, err)
		assert.LessOrEqual(t, len(results), 2)
	})

	t.Run("no duplicates", func(t *testing.T) {
		filter := principals.FilterList{}
		orderBy := fop.NewOrder(principals.DefaultOrderBy, principals.DefaultOrderDirection)
		results, err := store.List(ctx, filter, orderBy, fop.PageStringCursor{}, false)
		require.NoError(t, err)

		seen := make(map[string]bool)
		for _, r := range results {
			assert.False(t, seen[r.PrincipalID], "duplicate record: %s", r.PrincipalID)
			seen[r.PrincipalID] = true
		}
	})
}

